import styles from "./Switcher.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { InjectLocale } from "../../../../decorators/locale";
import { Classes } from "../../../../../common/constants/classes";
import { Key } from "../../../../../common/constants/keyboard";

@InjectLocale("Switcher")
class Switcher extends PureComponent {
  static propTypes = {
    switchOption: PropTypes.func.isRequired,
    leftOption: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    rightOption: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    currentOption: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    id: PropTypes.string.isRequired
  };

  onClick = () => {
    this.refs.button.focus();
    this.props.switchOption();
  };

  onKeyPress = e => {
    if (e.which === Key.SPACEBAR) {
      e.preventDefault();
      this.refs.button.click();
    }
  };

  get direction() {
    const { currentOption, leftOption } = this.props;

    return leftOption === currentOption ? styles.left : styles.right;
  }

  render() {
    const { leftOption, rightOption, currentOption, id } = this.props;
    const ariaLabel = this.locale.label;
    const ariaDescription = this.locale.description;

    return (
      <div
        className={classNames(styles.container, this.direction)}
        ref="button"
        tabIndex="0"
        role="button"
        aria-label={`${currentOption} ${ariaLabel}`}
        aria-describedby={`${styles.container}__${id}`}
        onClick={this.onClick}
        onKeyPress={this.onKeyPress}
      >
        <span className={styles["left-option"]} aria-hidden="true">
          {leftOption}
        </span>
        <div className={styles.toggle}>
          <span id={`${styles.container}__${id}`} className={Classes.VISUALLY_HIDDEN}>
            {ariaDescription}
          </span>
          <span className={styles.circle} />
        </div>
        <span className={styles["right-option"]} aria-hidden="true">
          {rightOption}
        </span>
      </div>
    );
  }
}

export default Switcher;
