/* eslint no-loop-func:off */

import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import { Classes } from "../../constants/classes";
import { Notifications } from "../../constants/notifications";
import { notification } from "../../utils/notification";
import { isDemoMode } from "../../constants/env";
import { GlobalEmitter } from "../../utils/event";
import { GlobalEvents } from "../../constants/event";
import { isIterable } from "../../../editor/utils/iterator";
import { sync } from "../../utils/async";

export default class InputFile extends PureComponent {
  static applicationType = "application";
  static imageType = "image";
  static audioType = "audio";
  static textType = "text";

  static mimeTypes = {
    allImages: `${InputFile.imageType}/*`,
    allAudio: `${InputFile.audioType}/*`,
    plainText: `${InputFile.textType}/plain`,
    json: `${InputFile.applicationType}/json`
  };

  static defaultProps = {
    multiple: true,
    onChange: () => {}
  };

  static propTypes = {
    onChange: PropTypes.func,
    multiple: PropTypes.bool,
    mimeType: PropTypes.array
  };

  static prepareFiles(files, types, size, callback) {
    types = InputFile.convertTypesToRegExp(types);

    for (const file of files) {
      try {
        InputFile.checkFileType(file, types);
        InputFile.checkFileSize(file, size);

        if (file.url) {
          const event = {};
          event.target = { readyState: FileReader.DONE, result: file.url };
          callback(event);
        } else {
          const reader = new FileReader();

          reader.onloadend = event => {
            if (event.target.readyState === FileReader.DONE) {
              callback(event);
            } else {
              notification(Notifications.UPLOAD_READ_FILE_ERROR);
              console.warn(Notifications.UPLOAD_READ_FILE_ERROR.text, file);
            }
          };

          reader.readAsDataURL(file, "utf-8");
        }
      } catch (error) {
        notification(error);
        console.warn(error.text, file);
      }
    }
  }

  static convertTypesToRegExp(types) {
    if (types) {
      if (!Array.isArray(types)) types = [types];
      return types.map(type => new RegExp(type.replace("*", ".+")));
    }

    return types;
  }

  static checkFileType(file, types) {
    if (types && !types.reduce((accum, type) => accum || type.test(file.type), false)) {
      throw Notifications.UPLOAD_TYPE_FILE_ERROR;
    }
  }

  static checkFileSize(file, size) {
    if (size && size < file.size) throw Notifications.UPLOAD_SIZE_FILE_ERROR(size);
  }

  state = {
    inputKey: Date.now()
  };

  click() {
    const { mimeType } = this.props;
    if (isDemoMode) {
      this.refs.button.click();
    } else {
      GlobalEmitter.emit(GlobalEvents.SELECT_FILES, mimeType, this.onFilesSelect);
    }
  }

  onFilesSelect = async files => {
    if (!isIterable(files)) files = [files];
    this.props.onChange(await this.normalizeFiles(files));
  };

  async normalizeFiles(files) {
    const fileList = [];
    const requests = [];
    for (const morphFile of files) {
      if (morphFile instanceof File) {
        fileList.push(morphFile);
      } else if (morphFile.file instanceof File && morphFile.url) {
        morphFile.file.url = morphFile.url;
        fileList.push(morphFile.file);
      } else if (morphFile.url) {
        requests.push(
          sync(morphFile.url, `Unable to process file at ${morphFile.url}`)
            .then(result => result.blob())
            .then(data => {
              const metadata = { type: data.type };
              const filename = morphFile.url.split("/").reverse()[0];
              const file = new File([data], filename, metadata);

              file.url = morphFile.url;
              fileList.push(file);
            })
            .catch(error => console.warn(error))
        );
      }
    }

    await Promise.all(requests);

    return fileList;
  }

  onChange = e => {
    this.props.onChange(e.target.files, e);
    this.setState({ inputKey: Date.now() });
  };

  get inputProps() {
    const { mimeType } = this.props;
    const props = {
      ref: "button",
      type: "file",
      key: this.state.inputKey,
      className: Classes.HIDDEN,
      onChange: this.onChange,
      multiple: this.props.multiple
    };

    props.accept = mimeType.join(",");

    return props;
  }

  render() {
    return <input {...this.inputProps} />;
  }
}
