import cloneDeep from "lodash/cloneDeep";
import shuffle from "lodash/shuffle";
import types from "./types";
import { FlashCards } from "../../../../common/constants/activities/flashcards";

const cloneCards = (state, options) => {
  const cards = [...state.cards];
  const currentCard = Object.assign({}, cards[state.currentCardIndex], options);

  cards[state.currentCardIndex] = currentCard;

  return cards;
};

export default {
  [types.SHOW_NEXT_CARD](state) {
    const nextCardIndex = state.currentCardIndex + 1;

    return {
      ...state,
      currentCardIndex: nextCardIndex !== state.cardsCount ? nextCardIndex : 0,
      cards: cloneCards(state, {
        flipped: false
      })
    };
  },
  [types.SHOW_PREV_CARD](state) {
    const lessZero = -1;
    const prevCardIndex = state.currentCardIndex - 1;

    return {
      ...state,
      currentCardIndex: prevCardIndex !== lessZero ? prevCardIndex : state.cardsCount - 1,
      cards: cloneCards(state, {
        flipped: false
      })
    };
  },
  [types.FLIP_CARD](state) {
    return {
      ...state,
      cards: cloneCards(state, {
        flipped: !state.cards[state.currentCardIndex].flipped
      })
    };
  },
  [types.SHUFFLE_CARDS](state) {
    return {
      ...state,
      currentCardIndex: 0,
      cards: shuffle(state.cards)
    };
  },
  [types.REMOVE_CARD](state) {
    const cards = [...state.cards];
    const cardsCount = state.cardsCount - 1;
    const { currentCardIndex } = state;

    cards.splice(state.currentCardIndex, 1);

    return {
      ...state,
      cardsCount,
      currentCardIndex: cardsCount === currentCardIndex ? currentCardIndex - 1 : currentCardIndex,
      cards
    };
  },
  [types.REFRESH_CARDS](state) {
    const cards = cloneDeep(state.initialCards);

    return {
      ...state,
      mode: FlashCards.FRONT_MODE,
      currentCardIndex: 0,
      cardsCount: cards.length,
      cards
    };
  },
  [types.SWITCH_MODE](state) {
    return {
      ...state,
      mode: state.mode === FlashCards.FRONT_MODE ? FlashCards.BACK_MODE : FlashCards.FRONT_MODE,
      cards: cloneCards(state, {
        flipped: false
      })
    };
  }
};
