import styles from "./OptionsButton.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Animations } from "../../../../../../common/constants/animations";
import { Classes } from "../../../../../../common/constants/classes";
import { Buttons } from "../../../../../constants/buttons";
import { sleep } from "../../../../../../common/utils/async";
import Menu from "../Menu/Menu";

export default class OptionsButton extends PureComponent {
  static propTypes = {
    shuffleCards: PropTypes.func.isRequired,
    refreshCards: PropTypes.func.isRequired,
    switchMode: PropTypes.func.isRequired,
    exportDeck: PropTypes.func.isRequired,
    mode: PropTypes.string.isRequired,
    shuffle: PropTypes.bool.isRequired
  };

  state = this.initialState;

  componentDidMount() {
    this.refs.container.addEventListener("focusout", this.onBlur);
  }

  onButtonClick = () => {
    if (this.state.menuClass === Classes.HIDDEN) {
      this.setState({
        menuClass: Animations.FADE_IN_UP,
        btnClass: buttonStyles["options-active"],
        menuExpanded: true
      });
    } else {
      this.setState(this.initialState);
    }
  };

  onBlur = async e => {
    if (!this.refs.container.contains(e.relatedTarget)) {
      await sleep(200);
      this.setState(this.initialState);
    }
  };

  get initialState() {
    return {
      menuClass: Classes.HIDDEN,
      btnClass: buttonStyles.options,
      menuExpanded: false
    };
  }

  render() {
    const { shuffleCards, refreshCards, switchMode, exportDeck, mode, shuffle } = this.props;
    const { menuClass } = this.state;

    return (
      <div ref="container" className={styles.container}>
        <Button
          id={Buttons.OPTIONS}
          className={classNames(styles.options, this.state.btnClass)}
          onClick={this.onButtonClick}
          hint={true}
          ariaExpanded={this.state.menuExpanded}
        />
        <Menu
          mode={mode}
          shuffle={shuffle}
          className={menuClass}
          shuffleCards={shuffleCards}
          refreshCards={refreshCards}
          switchMode={switchMode}
          exportDeck={exportDeck}
        />
      </div>
    );
  }
}
