import classNames from "classnames";
import { sleep } from "./async";

const getParentEl = options => {
  let parentEl = document.querySelector(`.${options.parentClassName}`);

  if (!parentEl) {
    parentEl = document.createElement("div");
    parentEl.className = options.parentClassName;
    document.body.appendChild(parentEl);
  }

  return parentEl;
};

const appendNewNotificationEl = (parentEl, options) => {
  const mainEl = document.createElement("div");
  const headerEl = document.createElement("div");
  const bodyEl = document.createElement("div");
  const closeEl = document.createElement("div");

  mainEl.className = classNames(options.className, `${options.className}--${options.type}`);
  headerEl.className = `${options.className}__header`;
  bodyEl.className = `${options.className}__body`;
  closeEl.className = `${options.className}__close`;

  headerEl.innerHTML = options.title;
  bodyEl.innerHTML = options.text;

  closeEl.addEventListener("mouseup", () => parentEl.removeChild(mainEl), false);

  headerEl.appendChild(closeEl);
  mainEl.appendChild(headerEl);
  mainEl.appendChild(bodyEl);
  parentEl.insertBefore(mainEl, parentEl.firstChild);

  return mainEl;
};

export const notification = async options => {
  const minTimeout = 1000;
  const defaultOptions = {
    parentClassName: "c-notifications",
    className: "c-notification",
    type: notification.INFO, // info|success|warning|error
    title: "",
    text: "",
    timeout: notification.TIMEOUT // hide notification timeout(if 0 don't hide)
  };

  const _options = Object.assign({}, defaultOptions, options);
  const parentEl = getParentEl(_options);
  const notificationEl = appendNewNotificationEl(parentEl, _options);

  // if the timeout is more than a second, then automatically closing the notification after the timeout
  if (Number.isFinite(_options.timeout) && _options.timeout > minTimeout) {
    await sleep(_options.timeout);
    if (notificationEl.parentNode) {
      parentEl.removeChild(notificationEl);
    }
  }
};

notification.TIMEOUT = 5000;
notification.INFO = "info";
notification.SUCCESS = "success";
notification.WARNING = "warning";
notification.ERROR = "error";
