import styles from "./Menu.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Buttons } from "../../../../../constants/buttons";
import { FlashCards } from "../../../../../../common/constants/activities/flashcards";
import Switcher from "../../../../common/components/Switcher/Switcher";

export default class Menu extends PureComponent {
  static propTypes = {
    className: PropTypes.string.isRequired,
    mode: PropTypes.string.isRequired,
    shuffle: PropTypes.bool.isRequired,
    shuffleCards: PropTypes.func.isRequired,
    refreshCards: PropTypes.func.isRequired,
    switchMode: PropTypes.func.isRequired,
    exportDeck: PropTypes.func.isRequired
  };

  get contentList() {
    const { shuffle } = this.props;

    let list = [
      <Button
        id={Buttons.REFRESH}
        key={Buttons.REFRESH}
        className={buttonStyles.refresh}
        onClick={this.props.refreshCards}
      >
        refresh
      </Button>,
      <Switcher
        id={Buttons.SWITCH}
        key={Buttons.SWITCH}
        leftOption={FlashCards.FRONT_MODE}
        rightOption={FlashCards.BACK_MODE}
        switchOption={this.props.switchMode}
        currentOption={this.props.mode}
      />,
      <Button
        id={Buttons.EXPORT}
        key={Buttons.EXPORT}
        className={buttonStyles.export}
        onClick={this.props.exportDeck}
      >
        export
      </Button>
    ];

    if (shuffle) {
      list.unshift(
        <Button
          id={Buttons.SHUFFLE}
          key={Buttons.SHUFFLE}
          className={buttonStyles.shuffle}
          onClick={this.props.shuffleCards}
        >
          shuffle
        </Button>
      );
    }

    return list;
  }

  get items() {
    return this.contentList.map((item, index) => (
      <li key={index} className={styles.item} role="menuitem">
        {item}
      </li>
    ));
  }

  render() {
    return (
      <ul className={classNames(styles.container, this.props.className)} role="menu">
        {this.items}
      </ul>
    );
  }
}
