import styles from "./Activity.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import { connect } from "react-redux";
import Hammer from "hammerjs";
import FileSaver from "file-saver";
import buildActions from "../../../store/actions";
import { isMobile } from "../../../../../../common/constants/user-agent";
import { Buttons } from "../../../../../constants/buttons";
import { Modals } from "../../../../../constants/modals";
import { Animations, OtherAnimations } from "../../../../../../common/constants/animations";
import { Key } from "../../../../../../common/constants/keyboard";
import { hasScroll } from "../../../../../utils/scroll";
import actionTypes from "../../../store/types";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import Modal from "../../../../common/components/Modal/Modal";
import ActivityHeader from "../../../../common/components/ActivityHeader/ActivityHeader";
import { Classes } from "../../../../../../common/constants/classes";
import { isFuture } from "../../../../../../common/constants/location";
import Card from "../Card/Card";
import InputFile from "../../../../../../common/components/InputFile/InputFile";

@connect(
  state => state,
  buildActions
)
class Activity extends PureComponent {
  static propTypes = {
    cards: PropTypes.array.isRequired,
    currentCardIndex: PropTypes.number.isRequired,
    cardsCount: PropTypes.number.isRequired,
    shuffle: PropTypes.bool.isRequired,
    name: PropTypes.string.isRequired,
    flipAnimation: PropTypes.string.isRequired,
    nextAnimation: PropTypes.string.isRequired,
    prevAnimation: PropTypes.string.isRequired,
    mode: PropTypes.string.isRequired,
    studentInstruction: PropTypes.string.isRequired,
    activityAlign: PropTypes.string,

    showNextCard: PropTypes.func.isRequired,
    showPrevCard: PropTypes.func.isRequired,
    removeCard: PropTypes.func.isRequired,
    shuffleCards: PropTypes.func.isRequired,
    flipCard: PropTypes.func.isRequired,
    refreshCards: PropTypes.func.isRequired,
    switchMode: PropTypes.func.isRequired
  };

  state = {
    cardAnimationClass: "",
    cardLabel: "",
    actionType: ""
  };
  cardContainer;
  touchManager;

  exportBlob;

  componentDidMount() {
    this.initTouchHandlers();
  }

  componentWillUnmount() {
    this.removeTouchHandlers();
  }

  initTouchHandlers = () => {
    if (isMobile) {
      this.touchManager = new Hammer.Manager(this.cardContainer, {
        recognizers: [
          [Hammer.Swipe, { direction: Hammer.DIRECTION_HORIZONTAL }],
          [Hammer.Tap, { taps: 2 }]
        ]
      });

      this.touchManager.on("swipeleft", this.showNextCard);
      this.touchManager.on("swiperight", this.showPrevCard);
      this.touchManager.on("tap", this.flipCard);
    }
  };

  removeTouchHandlers = () => {
    if (isMobile) {
      this.touchManager.off("swipeleft");
      this.touchManager.off("swiperight");
      this.touchManager.off("tap");
      this.touchManager.destroy();
    }
  };

  onMoveAnimationEnd = () => {
    let cardLabel;

    switch (this.state.actionType) {
      case actionTypes.REMOVE_CARD:
        cardLabel = `Card ${this.props.currentCardIndex + 1} was removed from the deck, ${this.props
          .cardsCount - 1} cards left.`;
        break;
      case actionTypes.FLIP_CARD:
        cardLabel = "The card was flipped.";
        break;
      case actionTypes.REFRESH_CARDS:
        cardLabel = "The deck was returned to its original state.";
        break;
      case actionTypes.SHUFFLE_CARDS:
        cardLabel = "The deck was shuffled";
        break;
      case actionTypes.SHOW_PREV_CARD:
      case actionTypes.SHOW_NEXT_CARD:
        cardLabel = `Card ${this.props.currentCardIndex + 1} of ${this.props.cardsCount}.`;
        break;
      default:
    }

    document.body.style.overflow = "auto";

    this.setState({
      cardAnimationClass: "",
      actionType: "",
      cardLabel
    });
  };

  onKeyDown = e => {
    switch (e.keyCode) {
      case Key.LEFT:
        this.showPrevCard(e);
        break;
      case Key.RIGHT:
        this.showNextCard(e);
        break;
      case Key.DELETE:
        this.props.cardsCount &&
          this.showModal(
            {
              type: Modals.DIALOG,
              title: "Delete card",
              content: "Do you want to delete current card?",
              ok: this.removeCard
            },
            e
          );
        break;
      case Key.S:
        if (e.altKey) {
          this.shuffleCards(e);
        }
        break;
      case Key.SPACEBAR:
        if (e.ctrlKey) {
          this.flipCard(e);
        }
        break;
      case Key.R:
        if (e.altKey) {
          this.refreshCards(e);
        }
        break;
      case Key.M:
        if (e.altKey) {
          this.switchMode(e);
        }
        break;
      case Key.E:
        if (e.ctrlKey && e.shiftKey) {
          this.exportDeck(e);
        }
        break;
      default:
    }
  };

  showNextCard = e => {
    e.preventDefault();
    if (!this.props.cardsCount) return;

    if (this.animationFinished) {
      const { nextAnimation, showNextCard } = this.props;

      if (!hasScroll()) {
        document.body.style.overflow = "hidden";
      }
      document.body.style.overflowX = "hidden";
      this.setState({
        cardAnimationClass: Animations[nextAnimation],
        cardLabel: "",
        actionType: actionTypes.SHOW_NEXT_CARD
      });
      showNextCard();
    }
    this.refs.card.content.scrollTop = 0;
  };

  showPrevCard = e => {
    e.preventDefault();
    if (this.props.cardsCount && this.animationFinished) {
      const { prevAnimation, showPrevCard } = this.props;

      this.setState({
        cardAnimationClass: Animations[prevAnimation],
        cardLabel: "",
        actionType: actionTypes.SHOW_PREV_CARD
      });
      showPrevCard();
    }
    this.refs.card.content.scrollTop = 0;
  };

  removeCard = e => {
    e.preventDefault();
    if (this.props.cardsCount && this.animationFinished) {
      this.setState({
        cardAnimationClass: Animations.FADE_IN,
        cardLabel: "",
        actionType: actionTypes.REMOVE_CARD
      });
      this.props.removeCard();
    }
  };

  shuffleCards = e => {
    if (this.props.cardsCount && this.animationFinished && this.props.shuffle) {
      e.preventDefault();

      this.setState({
        cardAnimationClass: OtherAnimations.SHAKE,
        actionType: actionTypes.SHUFFLE_CARDS
      });
      this.props.shuffleCards();
    }
  };

  flipCard = e => {
    if (this.props.cardsCount && this.animationFinished) {
      e.preventDefault();
      const { flipAnimation, flipCard } = this.props;

      if (!hasScroll) {
        document.body.style.overflow = "hidden";
      }
      document.body.style.overflowX = "hidden";
      this.setState({
        cardAnimationClass: Animations[flipAnimation],
        cardLabel: "",
        actionType: actionTypes.FLIP_CARD
      });
      this.refs.card.content.scrollTop = 0;
      flipCard();
    }
  };

  refreshCards = e => {
    e.preventDefault();

    this.setState({
      cardAnimationClass: Animations.PULSE,
      cardLabel: "",
      actionType: actionTypes.REFRESH_CARDS
    });
    this.props.refreshCards();
  };

  getJSONState = cards => {
    return JSON.stringify(cards).replace(/<[^>]*>?/gm, "");
  };

  getConcatenatedEntities = cards => {
    return cards.reduce(
      (accumulator, card) =>
        accumulator +
        (card.term.replace(/\n/gm, "").replace(/<[^>]*>?/gm, "") === "" &&
        card.definition.replace(/\n/gm, "").replace(/<[^>]*>?/gm, "") === ""
          ? ""
          : card.term.replace(/\n/gm, "").replace(/<[^>]*>?/gm, "") +
            "|" +
            card.definition.replace(/\n/gm, "").replace(/<[^>]*>?/gm, "") +
            "\n"),
      ""
    );
  };

  exportDeck = e => {
    e.preventDefault();

    if (!this.exportBlob) {
      const { cards } = this.props;

      const blobParameters = isFuture
        ? [[this.getJSONState(cards)], { type: InputFile.mimeTypes.json }]
        : [[this.getConcatenatedEntities(cards)], { type: InputFile.mimeTypes.plainText }];
      this.exportBlob = new Blob(...blobParameters);
    }

    FileSaver.saveAs(this.exportBlob, `deck.${isFuture ? "json" : "txt"}`);
  };

  switchMode(e) {
    e.preventDefault();
    this.setState({
      actionType: actionTypes.SWITCH_MODE
    });
    this.props.switchMode(e);
  }

  showModal = (options, e) => {
    e.preventDefault();
    this.dialogModal.show(options);
  };

  get animationFinished() {
    return !this.state.cardAnimationClass;
  }

  get adaHelperBlock() {
    return (
      <span className={Classes.VISUALLY_HIDDEN} aria-live="polite" aria-atomic="true">
        {this.state.cardLabel}
      </span>
    );
  }

  get previous() {
    return (
      <div className={classNames(styles.arrow, styles["arrow-previous"])}>
        <Button
          id={Buttons.PREV}
          className={buttonStyles.prev}
          onClick={this.showPrevCard}
          hint={true}
        />
      </div>
    );
  }

  get next() {
    return (
      <div className={classNames(styles.arrow, styles["arrow-next"])}>
        <Button
          id={Buttons.NEXT}
          className={buttonStyles.next}
          onClick={this.showNextCard}
          hint={true}
        />
      </div>
    );
  }

  get dialogModalBlock() {
    return <Modal ref={element => (this.dialogModal = element)} />;
  }

  get body() {
    const { currentCardIndex, cards, cardsCount, mode, shuffle, switchMode } = this.props;

    return (
      <div
        ref={element => {
          this.cardContainer = element;
        }}
        className={classNames(styles.body, this.state.cardAnimationClass)}
        onAnimationEnd={this.onMoveAnimationEnd}
      >
        {this.adaHelperBlock}
        {this.dialogModalBlock}
        <Card
          ref="card"
          currentCard={cards[currentCardIndex]}
          currentCardIndex={currentCardIndex}
          cardsCount={cardsCount}
          mode={mode}
          shuffle={shuffle}
          cardLabel={this.state.cardLabel}
          flipCard={this.flipCard}
          shuffleCards={this.shuffleCards}
          removeCard={this.removeCard}
          refreshCards={this.refreshCards}
          exportDeck={this.exportDeck}
          switchMode={switchMode}
          showModal={this.showModal}
        />
      </div>
    );
  }

  render() {
    const { cardsCount, activityAlign, studentInstruction, name: activityName } = this.props;

    return (
      <section tabIndex="0" className={styles.container} onKeyDown={this.onKeyDown}>
        <ActivityHeader activityName={activityName} studentInstruction={studentInstruction} />
        <div role="application" style={{ justifyContent: activityAlign }} className={styles.player}>
          {!!cardsCount && this.previous}
          {this.body}
          {!!cardsCount && this.next}
        </div>
      </section>
    );
  }
}

export default Activity;
