import { bindActionCreators } from "redux";
import types from "./types";

export const actions = {
  showNextCard() {
    return {
      type: types.SHOW_NEXT_CARD
    };
  },
  showPrevCard() {
    return {
      type: types.SHOW_PREV_CARD
    };
  },
  flipCard() {
    return {
      type: types.FLIP_CARD
    };
  },
  shuffleCards() {
    return {
      type: types.SHUFFLE_CARDS
    };
  },
  removeCard() {
    return {
      type: types.REMOVE_CARD
    };
  },
  refreshCards() {
    return {
      type: types.REFRESH_CARDS
    };
  },
  switchMode() {
    return {
      type: types.SWITCH_MODE
    };
  }
};

export default dispatcher => bindActionCreators(actions, dispatcher);
