import styles from "./Card.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Classes } from "../../../../../../common/constants/classes";
import { Animations } from "../../../../../../common/constants/animations";
import { isMobile, isMSBrowser } from "../../../../../../common/constants/user-agent";
import { PointerEvents } from "../../../../../../common/constants/event";
import { Modals } from "../../../../../constants/modals";
import { Buttons } from "../../../../../constants/buttons";
import { FlashCards } from "../../../../../../common/constants/activities/flashcards";
import ShortcutsButton from "../../../../common/components/ShortcutsButton/ShortcutsButton";
import OptionsButton from "../OptionsButton/OptionsButton";

export default class Card extends PureComponent {
  static contentMap = new Map();
  static noCardsMessage = "No cards available";

  static propTypes = {
    mode: PropTypes.string.isRequired,
    currentCardIndex: PropTypes.number.isRequired,
    cardsCount: PropTypes.number.isRequired,
    currentCard: PropTypes.object,
    shuffle: PropTypes.bool.isRequired,
    removeCard: PropTypes.func.isRequired,
    flipCard: PropTypes.func.isRequired,
    shuffleCards: PropTypes.func.isRequired,
    refreshCards: PropTypes.func.isRequired,
    switchMode: PropTypes.func.isRequired,
    exportDeck: PropTypes.func.isRequired,
    showModal: PropTypes.func.isRequired
  };

  state = Object.assign({}, this.initialState);
  contentElement;
  contentWrapper;
  currentCardContent = null;

  componentDidMount() {
    this.contentElement.addEventListener(PointerEvents.UP, this.onContentClick);
  }

  componentWillUnmount() {
    this.contentElement.removeEventListener(PointerEvents.UP, this.onContentClick);
  }

  onRemoveBtnClick = e => {
    // eslint-disable-next-line
    if (confirm("Do you want to delete current card?")) {
      this.props.removeCard(e);
    }
  };

  onContentClick = e => {
    const { showModal } = this.props;
    const target = e.target;

    if (target.tagName.toUpperCase() === "IMG" && !isMobile) {
      showModal(
        {
          type: Modals.IMAGE,
          source: target.getAttribute("src"),
          imageClassName: !isMSBrowser ? Animations.ZOOM_IN : ""
        },
        e
      );
    }
  };

  /**
   * It allows to determine whether such content was downloaded as: video, pictures, etc.
   * @param {any} cardContent - Contents of the card
   * @returns {any} - Сontent download options
   * @memberof Card
   */
  loadCardContent(cardContent) {
    const iframe = document.createElement("iframe");

    iframe.classList.add(Classes.VISUALLY_HIDDEN);
    document.body.appendChild(iframe);

    let resolve;
    const contentLoading = new Promise(r => (resolve = r));
    const iframeWindow = iframe.contentWindow;
    const iframeDocument = iframe.contentDocument;

    iframeDocument.open();
    iframeDocument.write(cardContent);
    iframeWindow.onload = () => {
      resolve();
      document.body.removeChild(iframe);
    };
    iframeDocument.close();

    return {
      content: iframeDocument.body.innerHTML,
      iframe,
      contentLoading
    };
  }

  get initialState() {
    return {
      listClass: Classes.HIDDEN,
      listExpanded: false
    };
  }

  get header() {
    const { currentCardIndex, cardsCount } = this.props;

    return (
      <div className={styles.header}>
        <div className={classNames(styles.controls, styles["controls-navigation"])}>
          {!isMobile && <ShortcutsButton excludeItems={{ shuffle: !this.props.shuffle }} />}
        </div>
        <div
          className={classNames(styles.controls, styles["controls-counter"])}
          aria-label={
            cardsCount ? `Card ${currentCardIndex + 1} of ${cardsCount}.` : Card.noCardsMessage
          }
        >
          <span aria-hidden="true">
            <span className={styles["current-card"]}>{currentCardIndex + 1}</span>
            <span className={styles["total-cards"]}> / {cardsCount}</span>
          </span>
        </div>
      </div>
    );
  }

  get cardContentOptions() {
    const {
      mode,
      currentCard: { term, definition, flipped }
    } = this.props;
    const reverseMode =
      mode === FlashCards.FRONT_MODE ? FlashCards.BACK_MODE : FlashCards.FRONT_MODE;
    const currentMode = flipped ? reverseMode : mode;
    let cardContent = currentMode === FlashCards.FRONT_MODE ? term : definition;

    // clearing a frame if it does not delete at full load
    if (this.currentCardContent !== cardContent) {
      const cardContentOptions = Card.contentMap.get(cardContent);

      if (cardContentOptions && cardContentOptions.iframe) {
        if (cardContentOptions.iframe.parentNode) {
          document.body.removeChild(cardContentOptions.iframe);
        }
        cardContentOptions.iframe = null;
      }

      this.currentCardContent = cardContent;
    }

    if (!Card.contentMap.has(cardContent)) {
      Card.contentMap.set(cardContent, this.loadCardContent(cardContent));
    }

    return Card.contentMap.get(cardContent);
  }

  get content() {
    return this.contentElement;
  }

  get body() {
    return (
      <div
        aria-live="polite"
        ref={element => (this.contentWrapper = element)}
        className={styles.body}
      >
        <div className={styles.content} ref={element => (this.contentElement = element)}>
          <div
            className={styles["content-inner"]}
            dangerouslySetInnerHTML={{
              __html: this.props.cardsCount ? this.cardContentOptions.content : Card.noCardsMessage
            }}
          />
        </div>
      </div>
    );
  }

  get footer() {
    const {
      flipCard,
      shuffleCards,
      refreshCards,
      switchMode,
      exportDeck,
      mode,
      shuffle
    } = this.props;

    return (
      <div className={styles.footer}>
        <div className={classNames(styles.controls, styles["controls-options"])}>
          <OptionsButton
            shuffleCards={shuffleCards}
            refreshCards={refreshCards}
            switchMode={switchMode}
            exportDeck={exportDeck}
            shuffle={shuffle}
            mode={mode}
          />
        </div>
        <div className={classNames(styles.controls, styles["controls-flip"])}>
          <Button id={Buttons.FLIP} className={buttonStyles.flip} onClick={flipCard} hint={true}>
            flip
          </Button>
        </div>
        <div className={classNames(styles.controls, styles["controls-remove"])}>
          <Button
            id={Buttons.REMOVE}
            className={buttonStyles.remove}
            onClick={this.onRemoveBtnClick}
            hint={true}
          />
        </div>
      </div>
    );
  }

  render() {
    return (
      <div className={styles.container}>
        {this.header}
        {this.body}
        {!!this.props.cardsCount && this.footer}
      </div>
    );
  }
}
